{"cmd":"cat > fullstack/backend/src/middleware/rateLimit.js << 'EOF'
import { config } from '../config.js';

const windows = {
  ip: new Map(),
  user: new Map()
};

function currentMinuteKey() {
  return Math.floor(Date.now() / 60000);
}

function incrementCounter(bucket, key) {
  const minuteKey = currentMinuteKey();
  const composite = `${key}:${minuteKey}`;
  const count = (bucket.get(composite) || 0) + 1;
  bucket.set(composite, count);
  return count;
}

function sweepOldEntries(bucket) {
  const minuteKey = currentMinuteKey();
  for (const key of bucket.keys()) {
    const parts = key.split(':');
    const keyMinute = Number(parts[parts.length - 1]);
    if (!Number.isNaN(keyMinute) && keyMinute < minuteKey - 2) {
      bucket.delete(key);
    }
  }
}

setInterval(() => {
  sweepOldEntries(windows.ip);
  sweepOldEntries(windows.user);
}, 45000).unref();

export async function rateLimit(ctx, next) {
  const ip = ctx.ip || ctx.request.ip || 'unknown';
  const ipCount = incrementCounter(windows.ip, ip);

  if (ipCount > config.rateLimits.ipPerMinute) {
    ctx.status = 429;
    ctx.body = { error: 'IP rate limit exceeded' };
    return;
  }

  const userId = ctx.state.user?.id;
  if (userId) {
    const userCount = incrementCounter(windows.user, String(userId));
    if (userCount > config.rateLimits.userPerMinute) {
      ctx.status = 429;
      ctx.body = { error: 'User rate limit exceeded' };
      return;
    }
  }

  await next();
}
EOF"}

{"cmd":"cat > fullstack/backend/src/routes/auth.js << 'EOF'
import Router from 'koa-router';
import { query } from '../db.js';
import { config } from '../config.js';
import { generateToken, hashPassword, validatePasswordComplexity, verifyPassword } from '../utils/crypto.js';
import { authRequired } from '../middleware/auth.js';

const router = new Router({ prefix: '/api/auth' });

router.post('/login', async (ctx) => {
  const { username, password } = ctx.request.body || {};
  if (!username || !password) {
    ctx.status = 400;
    ctx.body = { error: 'username and password are required' };
    return;
  }

  const users = await query(
    `SELECT u.id, u.username, u.password_hash, u.password_salt, u.full_name,
            u.location_code, u.department_code, r.name AS role_name
     FROM users u
     JOIN roles r ON r.id = u.role_id
     WHERE u.username = ? AND u.is_active = 1`,
    [username]
  );

  if (!users.length) {
    ctx.status = 401;
    ctx.body = { error: 'Invalid credentials' };
    return;
  }

  const user = users[0];
  const valid = verifyPassword(password, user.password_salt, user.password_hash);
  if (!valid) {
    ctx.status = 401;
    ctx.body = { error: 'Invalid credentials' };
    return;
  }

  const token = generateToken();
  const ttlHours = config.sessionTtlHours;
  await query(
    `INSERT INTO sessions (user_id, token, expires_at)
     VALUES (?, ?, DATE_ADD(UTC_TIMESTAMP(), INTERVAL ? HOUR))`,
    [user.id, token, ttlHours]
  );

  ctx.body = {
    token,
    expiresInHours: ttlHours,
    user: {
      id: user.id,
      username: user.username,
      fullName: user.full_name,
      role: user.role_name,
      locationCode: user.location_code,
      departmentCode: user.department_code
    }
  };
});

router.post('/logout', authRequired, async (ctx) => {
  await query('UPDATE sessions SET revoked_at = UTC_TIMESTAMP() WHERE id = ? AND revoked_at IS NULL', [ctx.state.user.sessionId]);
  ctx.body = { success: true };
});

router.post('/register', authRequired, async (ctx) => {
  if (ctx.state.user.role !== 'Administrator') {
    ctx.status = 403;
    ctx.body = { error: 'Only administrators can create users' };
    return;
  }

  const {
    username,
    full_name,
    password,
    role_name,
    location_code,
    department_code,
    email
  } = ctx.request.body || {};

  if (!username || !full_name || !password || !role_name || !location_code || !department_code) {
    ctx.status = 400;
    ctx.body = { error: 'Missing required fields' };
    return;
  }

  if (!validatePasswordComplexity(password)) {
    ctx.status = 400;
    ctx.body = {
      error: 'Password must be at least 12 chars and include uppercase, lowercase, number, special char'
    };
    return;
  }

  const roles = await query('SELECT id FROM roles WHERE name = ?', [role_name]);
  if (!roles.length) {
    ctx.status = 400;
    ctx.body = { error: 'Invalid role_name' };
    return;
  }

  const { salt, hash } = hashPassword(password);
  await query(
    `INSERT INTO users
      (username, email, full_name, password_hash, password_salt, role_id, location_code, department_code)
     VALUES (?, ?, ?, ?, ?, ?, ?, ?)`,
    [username, email || null, full_name, hash, salt, roles[0].id, location_code, department_code]
  );

  ctx.status = 201;
  ctx.body = { success: true };
});

export default router;
EOF"}

