export function enforceScope(options = {}) {
  const { locationField = 'location_code', departmentField = 'department_code' } = options;
  return async (ctx, next) => {
    const user = ctx.state.user;
    if (!user) {
      ctx.status = 401;
      ctx.body = { error: 'Unauthorized' };
      return;
    }

