<script setup>
import { reactive, ref } from 'vue';
import { apiGet, apiPost, apiPut } from '../services/api.js';

const props = defineProps({ token: { type: String, required: true } });

const message = ref('');
const form = reactive({
  customer_id: 1,
  vehicle_type: 'light',
  scheduled_at: '',
  notes: ''
});
const seats = ref([]);
const bayRows = ref([]);

function toUtcIso(localValue) {
  if (!localValue) return '';
  return new Date(localValue).toISOString();
}

async function refresh() {
  const data = await apiGet('/api/dashboard/coordinator-view', props.token);
  seats.value = (data.seats || []).map((s) => ({ ...s }));
  bayRows.value = data.bayUtilization || [];
}

async function schedule() {
  message.value = '';
  try {
    const payload = {
      customer_id: Number(form.customer_id),
      vehicle_type: form.vehicle_type,
      scheduled_at: toUtcIso(form.scheduled_at),
      notes: form.notes
    };
    const res = await apiPost('/api/coordinator/appointments/schedule', props.token, payload);
    message.value = `Scheduled appointment #${res.appointmentId} (Bay ${res.bayResourceId})`;
    await refresh();
  } catch (err) {
    message.value = err.message;
  }
}

function onDragStart(seat, event) {
  event.dataTransfer?.setData('text/plain', String(seat.id));
}

function onDrop(targetSeat, event) {
  const sourceId = Number(event.dataTransfer?.getData('text/plain'));
  const source = seats.value.find((s) => s.id === sourceId);
  if (!source || source.id === targetSeat.id) return;

  const tempX = source.x_pos;
  const tempY = source.y_pos;
  source.x_pos = targetSeat.x_pos;
  source.y_pos = targetSeat.y_pos;
  targetSeat.x_pos = tempX;
  targetSeat.y_pos = tempY;
}

async function saveSeats() {
  await apiPut('/api/coordinator/waiting-room/seats', props.token, { seats: seats.value });
  message.value = 'Seat layout saved';
}

await refresh();
</script>

